    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <h4 class="section-title">Security</h4>
        <p class="section-subtitle">Manage your password, two-factor authentication, and sessions.</p>

        <!-- Change Password -->
        <div class="settings-card">
            <div class="expandable-header" @onclick="() => _changePasswordExpanded = !_changePasswordExpanded">
                <h6 class="mb-0">Change Password</h6>
                <span class="expand-icon">@(_changePasswordExpanded ? "▲" : "▼")</span>
            </div>

            @if (_securitySettings?.LastPasswordChange is not null)
            {
                <small class="text-muted">Last changed @_securitySettings.LastPasswordChange.Value.ToString("MMM dd, yyyy")</small>
            }

            @if (_changePasswordExpanded)
            {
                <div class="mt-3">
                    <div class="form-group">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="form-group">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="form-group">
