                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary mt-2" @onclick="ChangePassword">Update Password</button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="settings-card mt-3">
            <div class="toggle-row">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="small">
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>
        </div>

        <!-- Active Sessions -->
        <div class="settings-card mt-3">
            <h6>Active Sessions</h6>
            @if (_securitySettings?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-sm align-middle mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _securitySettings.Sessions)
                            {
                                var isCurrentSession = session == _securitySettings.Sessions[0];
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrentSession)
                                        {
                                            <span class="badge bg-info ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrentSession)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => RequestRevokeSession(session.Id, session.Device)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted">No active sessions.</p>
            }
        </div>
    };

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private RenderFragment RenderAppearanceSection() => __builder =>
