/* ── Sidebar ── */

.settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    background: #f8f9fa;
    border-radius: 0.75rem;
    padding: 1rem 0.5rem;
    height: fit-content;
    position: sticky;
    top: 1rem;
}

.sidebar-title {
    padding: 0.25rem 0.75rem 0.75rem;
    font-weight: 700;
    color: #333;
    border-bottom: 1px solid #e9ecef;
    margin-bottom: 0.5rem;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    width: 100%;
    padding: 0.6rem 0.75rem;
    border: none;
    background: none;
    border-radius: 0.5rem;
    cursor: pointer;
    font-size: 0.95rem;
    color: #555;
    transition: all 0.15s ease;
    text-align: left;
}

.sidebar-item:hover {
