{"file_text": "@page "/settings"
@using sv_8f9ad2bcd249432ea4fa1652678c0b35.Models
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Sidebar Navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        @foreach (var section in _sections)
        {
            <button class="sidebar-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => SetActiveSection(section.Key)">
                <span class="sidebar-icon">@section.Value.Icon</span>
                <span>@section.Value.Label</span>
            </button>
        }
    </nav>

    <!-- Main Content Area -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        <!-- Toast -->
        @if (_showToast)
        {
            <div class="settings-toast @(_toastType)" @onclick="() => _showToast = false">
                @_toastMessage
            </div>
        }
    </div>
</div>

<!-- Session Revoke Confirmation Modal -->
@if (_showRevokeConfirm)
{
    <div class="modal-backdrop show" @onclick="() => _showRevokeConfirm = false"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="() => _showRevokeConfirm = false"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session on <strong>@_revokeSessionDevice</strong>? The user will be signed out immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="() => _showRevokeConfirm = false">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevokeSession">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    // Toast state
    private bool _showToast;
    private string _toastMessage = "";
    private string _toastType = "success";
    private CancellationTokenSource? _toastCts;

    // Profile state
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private UserProfile? _savedProfile;

    // Notification state
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    // Security state
    private SecuritySettings? _securitySettings;
    private bool _twoFactorEnabled;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _showRevokeConfirm;
    private string _revokeSessionId = "";
    private string _revokeSessionDevice = "";

    // Appearance state
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    // Sidebar sections
    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["profile"] = ("Profile", "👤"),
        ["notifications"] = ("Notifications", "🔔"),
        ["security"] = ("Security", "🔒"),
        ["appearance"] = ("Appearance", "🎨"),
    };

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionData("profile");
        _loading = false;
    }

    private async Task SetActiveSection(string section)
    {
        if (ActiveSection == section) return;
        _loading = true;
        ActiveSection = section;
        await LoadSectionData(section);
        _loading = false;
    }

    private async Task LoadSectionData(string section)
    {
        switch (section)
        {
            case "profile":
                var profile = await SettingsService.GetProfileAsync();
                _savedProfile = profile;
                _displayName = profile.DisplayName;
                _email = profile.Email;
                _avatarUrl = profile.AvatarUrl;
                _bio = profile.Bio;
                break;
            case "notifications":
                var prefs = await SettingsService.GetNotificationPrefsAsync();
                _emailNotifications = prefs.EmailNotifications;
                _pushNotifications = prefs.PushNotifications;
                _weeklyDigest = prefs.WeeklyDigest;
                _allChannels = [.. prefs.MutedChannels];
                _mutedChannels = [.. prefs.MutedChannels];
                break;
            case "security":
                _securitySettings = await SettingsService.GetSecuritySettingsAsync();
                _twoFactorEnabled = _securitySettings.TwoFactorEnabled;
                _changePasswordExpanded = false;
                _currentPassword = "";
                _newPassword = "";
                _confirmPassword = "";
                break;
            case "appearance":
                var appearance = await SettingsService.GetAppearanceAsync();
                _theme = appearance.Theme;
                _fontSize = appearance.FontSize;
                _language = appearance.Language;
                _compactMode = appearance.CompactMode;
                break;
        }
    }

    private async Task ShowToast(string message, string type = "success")
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastType = type;
        _showToast = true;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _showToast = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    // ── Profile ──

    private async Task SaveProfile()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is null) return;
        _displayName = _savedProfile.DisplayName;
        _email = _savedProfile.Email;
        _avatarUrl = _savedProfile.AvatarUrl;
        _bio = _savedProfile.Bio;
    }

    // ── Notifications ──

    private void ToggleMuteChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved!");
    }

    // ── Security ──

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            await ShowToast("Please fill in all password fields.", "error");
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            await ShowToast("New passwords do not match.", "error");
            return;
        }

        if (_newPassword.Length < 8)
        {
            await ShowToast("Password must be at least 8 characters.", "error");
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changePasswordExpanded = false;
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Password updated successfully!");
    }

    private void RequestRevokeSession(string sessionId, string device)
    {
        _revokeSessionId = sessionId;
        _revokeSessionDevice = device;
        _showRevokeConfirm = true;
    }

    private async Task ConfirmRevokeSession()
    {
        await SettingsService.RevokeSessionAsync(_revokeSessionId);
        _showRevokeConfirm = false;
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Session revoked.");
    }

    // ── Appearance ──

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved!");
    }

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private string PreviewBackground => _theme switch
    {
        "Dark" => "#1e1e2e",
        "System" => "#f0f0f5",
        _ => "#ffffff"
    };

    private string PreviewTextColor => _theme == "Dark" ? "#cdd6f4" : "#333333";

    // ── Render fragments ──

    private RenderFragment RenderProfileSection() => __builder =>
    {
        <h4 class="section-title">Profile</h4>
        <p class="section-subtitle">Manage your public profile information.</p>

        <div class="settings-card">
            <div class="avatar-section">
                <div class="avatar-preview">
                    <img src="@_avatarUrl" alt="Avatar" onerror="this.style.display='none'" />
                </div>
                <div class="avatar-url-display">
                    <small class="text-muted">@_avatarUrl</small>
                </div>
            </div>

            <div class="form-group">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>

            <div class="form-group">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>

            <div class="form-group">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </div>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <h4 class="section-title">Notifications</h4>
        <p class="section-subtitle">Choose how and when you want to be notified.</p>

        <div class="settings-card">
            <div class="toggle-row">
                <div>
                    <strong>Email Notifications</strong>
                    <div class="text-muted small">Receive notifications via email</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_emailNotifications"
                           @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                </div>
            </div>

            <div class="toggle-row">
                <div>
                    <strong>Push Notifications</strong>
                    <div class="text-muted small">Receive push notifications in the browser</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_pushNotifications"
                           @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                </div>
            </div>

            <div class="toggle-row">
                <div>
                    <strong>Weekly Digest</strong>
                    <div class="text-muted small">Get a summary of activity every week</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_weeklyDigest"
                           @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                </div>
            </div>
        </div>

        <div class="settings-card mt-3">
            <h6>Muted Channels</h6>
            <p class="text-muted small">Uncheck channels you want to receive notifications from.</p>
            @foreach (var channel in _allChannels)
            {
